seedUsers();

// GraphQL Schema
const typeDefs = gql`
  enum UserRole {
    ADMIN
    MODERATOR
    USER
  }

  enum UserStatus {
    ACTIVE
    INACTIVE
    SUSPENDED
  }

  enum SortField {
    NAME
    EMAIL
    CREATED_AT
    ROLE
    STATUS
  }

  enum SortOrder {
    ASC
    DESC
  }

  type User {
    id: ID!
    name: String!
    email: String!
    role: UserRole!
    status: UserStatus!
    createdAt: String!
  }

  type UserBatchResult {
    found: [User!]!
    notFoundIds: [ID!]!
    totalRequested: Int!
    totalFound: Int!
  }

  type PaginatedUsers {
    users: [User!]!
    totalCount: Int!
    page: Int!
    pageSize: Int!
    totalPages: Int!
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
  }

  type DashboardStats {
    totalUsers: Int!
    activeUsers: Int!
    inactiveUsers: Int!
    suspendedUsers: Int!
    adminCount: Int!
    moderatorCount: Int!
    regularUserCount: Int!
  }

  type BulkOperationResult {
    successIds: [ID!]!
    failedIds: [ID!]!
    totalProcessed: Int!
    totalSuccess: Int!
    totalFailed: Int!
  }

  input UserInput {
    name: String!
    email: String!
    role: UserRole
    status: UserStatus
  }

  input UserUpdateInput {
    name: String
    email: String
    role: UserRole
    status: UserStatus
  }

  input BulkUserInput {
    name: String!
    email: String!
    role: UserRole
    status: UserStatus
  }

  input UserFilterInput {
    roles: [UserRole!]
    statuses: [UserStatus!]
    nameContains: String
    emailContains: String
  }

  input SortInput {
    field: SortField!
    order: SortOrder!
  }

  type Query {
    # Single user query
    user(id: ID!): User

    # Batch query - fetch multiple users by IDs array (reduces round trips)
    users(ids: [ID!]!): UserBatchResult!

    # Paginated query with filtering and sorting for dashboard lists
    listUsers(
      page: Int
      pageSize: Int
      filter: UserFilterInput
      sort: SortInput
    ): PaginatedUsers!

    # Filter users by multiple roles at once
    usersByRoles(roles: [UserRole!]!): [User!]!

    # Filter users by multiple statuses at once
    usersByStatuses(statuses: [UserStatus!]!): [User!]!

    # Dashboard statistics
    dashboardStats: DashboardStats!

    # Search users by multiple emails
    usersByEmails(emails: [String!]!): UserBatchResult!
  }

  type Mutation {
    # Create single user
    createUser(input: UserInput!): User!

    # Bulk create users - accepts array of user inputs
    bulkCreateUsers(inputs: [BulkUserInput!]!): [User!]!

    # Update single user
    updateUser(id: ID!, input: UserUpdateInput!): User

    # Bulk update - update multiple users' status at once
    bulkUpdateStatus(ids: [ID!]!, status: UserStatus!): BulkOperationResult!

    # Bulk update - update multiple users' role at once
    bulkUpdateRole(ids: [ID!]!, role: UserRole!): BulkOperationResult!

    # Delete single user
    deleteUser(id: ID!): Boolean!

    # Bulk delete - delete multiple users at once
    bulkDeleteUsers(ids: [ID!]!): BulkOperationResult!
  }
`;

// Resolvers
const resolvers = {
  Query: {
    // Single user fetch
    user: (_, { id }) => {
      return users.get(id) || null;
    },

    // Batch fetch: query users(ids: [1,2,3,4,5...100])
    // Efficiently fetches multiple users in a single request
    users: (_, { ids }) => {
      const MAX_BATCH_SIZE = 500;

      if (ids.length > MAX_BATCH_SIZE) {
        throw new Error(`Batch size exceeds maximum of ${MAX_BATCH_SIZE}. Requested: ${ids.length}`);
      }

      // Deduplicate IDs
      const uniqueIds = [...new Set(ids)];

      const found = [];
      const notFoundIds = [];

      uniqueIds.forEach(id => {
        const user = users.get(id);
        if (user) {
          found.push(user);
        } else {
          notFoundIds.push(id);
        }
      });

      return {
        found,
        notFoundIds,
        totalRequested: uniqueIds.length,
        totalFound: found.length,
      };
    },

    // Paginated listing with filter and sort for dashboard tables
    listUsers: (_, { page = 1, pageSize = 20, filter, sort }) => {
      const MAX_PAGE_SIZE = 100;
      const effectivePageSize = Math.min(pageSize, MAX_PAGE_SIZE);

      let allUsers = Array.from(users.values());

      // Apply filters
      if (filter) {
        if (filter.roles && filter.roles.length > 0) {
          allUsers = allUsers.filter(u => filter.roles.includes(u.role));
        }
        if (filter.statuses && filter.statuses.length > 0) {
          allUsers = allUsers.filter(u => filter.statuses.includes(u.status));
        }
        if (filter.nameContains) {
          const search = filter.nameContains.toLowerCase();
          allUsers = allUsers.filter(u => u.name.toLowerCase().includes(search));
        }
        if (filter.emailContains) {
          const search = filter.emailContains.toLowerCase();
          allUsers = allUsers.filter(u => u.email.toLowerCase().includes(search));
        }
      }

      // Apply sorting
      if (sort) {
        const sortFieldMap = {
          NAME: 'name',
          EMAIL: 'email',
          CREATED_AT: 'createdAt',
          ROLE: 'role',
          STATUS: 'status',
        };

        const field = sortFieldMap[sort.field];
        const multiplier = sort.order === 'ASC' ? 1 : -1;

        allUsers.sort((a, b) => {
          const aVal = a[field] || '';
          const bVal = b[field] || '';
          if (aVal < bVal) return -1 * multiplier;
          if (aVal > bVal) return 1 * multiplier;
          return 0;
        });
      }

      const totalCount = allUsers.length;
      const totalPages = Math.ceil(totalCount / effectivePageSize);
      const startIndex = (page - 1) * effectivePageSize;
      const paginatedUsers = allUsers.slice(startIndex, startIndex + effectivePageSize);

      return {
        users: paginatedUsers,
        totalCount,
        page,
        pageSize: effectivePageSize,
        totalPages,
        hasNextPage: page < totalPages,
        hasPreviousPage: page > 1,
      };
    },

    // Query users by multiple roles at once
    usersByRoles: (_, { roles }) => {
      return Array.from(users.values()).filter(u => roles.includes(u.role));
    },

    // Query users by multiple statuses at once
    usersByStatuses: (_, { statuses }) => {
      return Array.from(users.values()).filter(u => statuses.includes(u.status));
    },

    // Dashboard aggregation stats
    dashboardStats: () => {
      const allUsers = Array.from(users.values());
      return {
        totalUsers: allUsers.length,
        activeUsers: allUsers.filter(u => u.status === 'ACTIVE').length,
        inactiveUsers: allUsers.filter(u => u.status === 'INACTIVE').length,
        suspendedUsers: allUsers.filter(u => u.status === 'SUSPENDED').length,
        adminCount: allUsers.filter(u => u.role === 'ADMIN').length,
        moderatorCount: allUsers.filter(u => u.role === 'MODERATOR').length,
        regularUserCount: allUsers.filter(u => u.role === 'USER').length,
      };
    },

    // Batch fetch by emails
    usersByEmails: (_, { emails }) => {
      const MAX_BATCH_SIZE = 500;

      if (emails.length > MAX_BATCH_SIZE) {
        throw new Error(`Batch size exceeds maximum of ${MAX_BATCH_SIZE}. Requested: ${emails.length}`);
      }

      const uniqueEmails = [...new Set(emails.map(e => e.toLowerCase()))];
      const allUsers = Array.from(users.values());

      const found = [];
      const foundEmails = new Set();

      allUsers.forEach(user => {
        if (uniqueEmails.includes(user.email.toLowerCase())) {
          found.push(user);
          foundEmails.add(user.email.toLowerCase());
        }
      });

      const notFoundIds = uniqueEmails.filter(e => !foundEmails.has(e));

      return {
        found,
        notFoundIds,
        totalRequested: uniqueEmails.length,
        totalFound: found.length,
      };
    },
  },

  Mutation: {
    // Create single user
    createUser: (_, { input }) => {
      // Check for duplicate email
      const existingUser = Array.from(users.values()).find(
        u => u.email.toLowerCase() === input.email.toLowerCase()
      );
      if (existingUser) {
        throw new Error(`User with email ${input.email} already exists`);
      }

      const newUser = {
        id: uuidv4(),
        name: input.name,
        email: input.email,
        role: input.role || 'USER',
        status: input.status || 'ACTIVE',
        createdAt: new Date().toISOString(),
      };

      users.set(newUser.id, newUser);
      return newUser;
    },

    // Bulk create - accepts array of user inputs
    bulkCreateUsers: (_, { inputs }) => {
      const MAX_BULK_SIZE = 100;

      if (inputs.length > MAX_BULK_SIZE) {
        throw new Error(`Bulk create size exceeds maximum of ${MAX_BULK_SIZE}. Requested: ${inputs.length}`);
      }

      const existingEmails = new Set(
        Array.from(users.values()).map(u => u.email.toLowerCase())
      );

      // Check for duplicates within the batch
      const batchEmails = new Set();
      inputs.forEach(input => {
        const email = input.email.toLowerCase();
        if (existingEmails.has(email)) {
          throw new Error(`User with email ${input.email} already exists`);
        }
        if (batchEmails.has(email)) {
          throw new Error(`Duplicate email ${input.email} in batch`);
        }
        batchEmails.add(email);
      });

      const createdUsers = inputs.map(input => {
        const newUser = {
          id: uuidv4(),
          name: input.name,
          email: input.email,
          role: input.role || 'USER',
          status: input.status || 'ACTIVE',
          createdAt: new Date().toISOString(),
        };
        users.set(newUser.id, newUser);
        return newUser;
      });

      return createdUsers;
    },

    // Update single user
    updateUser: (_, { id, input }) => {
      const user = users.get(id);
      if (!user) return null;

      if (input.email) {
        const existingUser = Array.from(users.values()).find(
          u => u.email.toLowerCase() === input.email.toLowerCase() && u.id !== id
        );
        if (existingUser) {
          throw new Error(`User with email ${input.email} already exists`);
        }
      }

      const updatedUser = {
        ...user,
        ...(input.name !== undefined && { name: input.name }),
        ...(input.email !== undefined && { email: input.email }),
        ...(input.role !== undefined && { role: input.role }),
        ...(input.status !== undefined && { status: input.status }),
      };

      users.set(id, updatedUser);
      return updatedUser;
    },

    // Bulk update status for multiple users
    bulkUpdateStatus: (_, { ids, status }) => {
      const MAX_BULK_SIZE = 500;

      if (ids.length > MAX_BULK_SIZE) {
        throw new Error(`Bulk update size exceeds maximum of ${MAX_BULK_SIZE}. Requested: ${ids.length}`);
      }

      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];

      uniqueIds.forEach(id => {
        const user = users.get(id);
        if (user) {
          users.set(id, { ...user, status });
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      });

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },

    // Bulk update role for multiple users
    bulkUpdateRole: (_, { ids, role }) => {
      const MAX_BULK_SIZE = 500;

      if (ids.length > MAX_BULK_SIZE) {
        throw new Error(`Bulk update size exceeds maximum of ${MAX_BULK_SIZE}. Requested: ${ids.length}`);
      }

      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];

      uniqueIds.forEach(id => {
        const user = users.get(id);
        if (user) {
          users.set(id, { ...user, role });
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      });

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },

    // Delete single user
    deleteUser: (_, { id }) => {
      if (!users.has(id)) return false;
      users.delete(id);
      return true;
    },

    // Bulk delete multiple users
    bulkDeleteUsers: (_, { ids }) => {
      const MAX_BULK_SIZE = 500;

      if (ids.length > MAX_BULK_SIZE) {
        throw new Error(`Bulk delete size exceeds maximum of ${MAX_BULK_SIZE}. Requested: ${ids.length}`);
      }

      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];

      uniqueIds.forEach(id => {
        if (users.has(id)) {
          users.delete(id);
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      });

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },
  },
};

// Create and start the Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: true,
  formatError: (error) => {
    console.error('GraphQL Error:', error.message);
    return {
      message: error.message,
      code: error.extensions?.code || 'INTERNAL_SERVER_ERROR',
      path: error.path,
    };
  },
});

